const item = $input.item.json.data[0];

// 1. Process Skills into HTML pills
let skillsHtml = '';
if (item.Required_Skills) {
  skillsHtml = item.Required_Skills.split(',')
    .map(skill => `<span class="skill-pill">${skill.trim()}</span>`)
    .join('\n      ');
} else {
  skillsHtml = '<span class="text-muted">Not specified</span>';
}

// 2. Fetch nested department properties safely
const departmentName = item.Department_Name ? item.Department_Name.name : 'N/A';

// 3. Fallback handlers for common null values
const salary = item.Salary || 'Competitive';
const city = item.City || 'Remote';
const country = item.Country || '';
const jobType = item.Job_Type || 'Full-Time';

// 4. Format Description: handle newlines and bullets
let descriptionHtml = item.Job_Description || 'No description provided.';
if (!descriptionHtml.includes('<p>') && !descriptionHtml.includes('</div>') && !descriptionHtml.includes('<br>')) {
  descriptionHtml = descriptionHtml
    .split(/\n\s*\n/)
    .map(para => {
      const lines = para.split('\n');
      if (lines.length > 1 && lines.every(line => /^\s*[\-\*•✔].*/.test(line))) {
        const listItems = lines.map(line => `<li>${line.replace(/^\s*[\-\*•✔]\s*/, '')}</li>`).join('');
        return `<ul>${listItems}</ul>`;
      }
      return `<p>${para.replace(/\n/g, '<br>')}</p>`;
    })
    .join('\n');
}

// 5. HTML Template with inline CSS
const htmlContent = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <title>Job Description - ${item.Posting_Title || item.Job_Opening_Name}</title>
  <link rel="preconnect" href="https://fonts.googleapis.com">
  <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>
  <link href="https://fonts.googleapis.com/css2?family=Outfit:wght@400;500;600;700&display=swap" rel="stylesheet">
  <style>
    :root {
      --primary: #1e3a8a;
      --primary-light: #eff6ff;
      --text-main: #1f2937;
      --text-muted: #6b7280;
      --bg-card: #f9fafb;
      --border-color: #e5e7eb;
    }
    body {
      font-family: 'Outfit', sans-serif;
      color: var(--text-main);
      line-height: 1.6;
      margin: 0;
      padding: 40px;
      background-color: #ffffff;
    }
    .container {
      max-width: 800px;
      margin: 0 auto;
    }
    .header {
      border-bottom: 3px solid var(--primary);
      padding-bottom: 20px;
      margin-bottom: 30px;
    }
    .header-meta {
      font-size: 0.85rem;
      color: var(--primary);
      text-transform: uppercase;
      font-weight: 700;
      letter-spacing: 0.05em;
      margin-bottom: 6px;
    }
    .job-title {
      font-size: 2.25rem;
      font-weight: 700;
      margin: 0 0 8px 0;
      color: #0f172a;
    }
    .meta-grid {
      display: grid;
      grid-template-columns: repeat(2, 1fr);
      gap: 12px;
      margin-bottom: 30px;
    }
    .meta-card {
      background-color: var(--bg-card);
      border: 1px solid var(--border-color);
      border-radius: 8px;
      padding: 12px 16px;
    }
    .meta-label {
      font-size: 0.75rem;
      font-weight: 600;
      color: var(--text-muted);
      text-transform: uppercase;
      display: block;
      margin-bottom: 4px;
    }
    .meta-value {
      font-size: 0.95rem;
      font-weight: 500;
      color: #0f172a;
    }
    .section-title {
      font-size: 1.15rem;
      font-weight: 600;
      color: var(--primary);
      border-bottom: 1px solid var(--border-color);
      padding-bottom: 6px;
      margin-top: 32px;
      margin-bottom: 16px;
      text-transform: uppercase;
      letter-spacing: 0.02em;
    }
    .description-content {
      font-size: 0.95rem;
    }
    .description-content p {
      margin-top: 0;
      margin-bottom: 16px;
    }
    .description-content ul {
      margin-top: 0;
      margin-bottom: 16px;
      padding-left: 20px;
    }
    .description-content li {
      margin-bottom: 8px;
    }
    .skills-container {
      display: flex;
      flex-wrap: wrap;
      gap: 8px;
      margin-top: 12px;
    }
    .skill-pill {
      background-color: var(--primary-light);
      color: var(--primary);
      font-size: 0.8rem;
      font-weight: 600;
      padding: 6px 12px;
      border-radius: 9999px;
      border: 1px solid #dbeafe;
    }
    .footer {
      margin-top: 60px;
      border-top: 1px solid var(--border-color);
      padding-top: 16px;
      text-align: center;
      font-size: 0.75rem;
      color: var(--text-muted);
    }
    @media print {
      body {
        padding: 0;
      }
      .meta-card {
        page-break-inside: avoid;
      }
      .section-title {
        page-break-after: avoid;
      }
    }
  </style>
</head>
<body>
  <div class="container">
    <div class="header">
      <div class="header-meta">Job Reference ID: ${item.Job_Opening_ID || 'N/A'}</div>
      <h1 class="job-title">${item.Posting_Title || item.Job_Opening_Name}</h1>
    </div>

    <div class="meta-grid">
      <div class="meta-card">
        <span class="meta-label">Location</span>
        <span class="meta-value">${city}${country ? ', ' + country : ''}</span>
      </div>
      <div class="meta-card">
        <span class="meta-label">Job Type</span>
        <span class="meta-value">${jobType}</span>
      </div>
      <div class="meta-card">
        <span class="meta-label">Department</span>
        <span class="meta-value">${departmentName}</span>
      </div>
      <div class="meta-card">
        <span class="meta-label">Salary Range</span>
        <span class="meta-value">${salary}</span>
      </div>
    </div>

    <div class="section-title">About the Role</div>
    <div class="description-content">
      ${descriptionHtml}
    </div>

    <div class="section-title">Key Requirements & Skills</div>
    <div class="skills-container">
      ${skillsHtml}
    </div>

    <div class="footer">
      Generated via YZEE Labs Recruitment Operations. Confidential & Proprietary.
    </div>
  </div>
</body>
</html>`;

return [{
  json: {
    html: htmlContent,
    filename: `Job_Description_${item.Job_Opening_ID || item.id}.pdf`
  },
  binary: {
    data: {
      data: Buffer.from(htmlContent).toString('base64'),
      mimeType: 'text/html',
      fileName: 'index.html'
    }
  }
}];
